    return sell > storeValue + ppMinAdv;                               // A) ulozeni nema smysl -> prodej prebytek
}

// FIX (12.5.2026): NIBE pick podle CENY (§ 8.3 r. 916 "DUM BUDE NATOPENY ZA CO NEJLEPSI CENU").
// Bug pred fixem: hlavni iterace brala prvni-prijde-prvni-bere → NIBE v drazsich hodinach.
// Greedy pick: nejlevnejsi solarni hodina prvni, blokovat sousedni (cooldown 1h per § 4.9.1 r. 405).
// Pokud cooldown zablokuje vsechny dalsi kandidaty, picknu mene nez nibeZbyva — preferuje
// nejlevnejsi cenu pred maxim cyklu (user explicitne 12.5.2026: "v te nejlevnejsi hodine").
var nibeAssigned = {};
if (x.nibeK > 0 && !C.letni && nibeZbyva > 0) {
    var nibeCands = [];
    for (var ni = 0; ni < hp.length; ni++) {
        if (x.sO[ni] && hp[ni].levelBuy < C.DRAHA) nibeCands.push({off: ni, lvl: hp[ni].levelBuy, b: hp[ni].buy});
    }
    nibeCands.sort(function(a, b) { return a.lvl - b.lvl || a.b - b.b; });
    var nibePicked = 0;
    for (var nc = 0; nc < nibeCands.length && nibePicked < nibeZbyva; nc++) {
        var noff = nibeCands[nc].off;
        if (nibeAssigned[noff - 1] || nibeAssigned[noff + 1]) continue;
        nibeAssigned[noff] = true; nibePicked++;
    }
}

var consAt = x.consAt || function(hour) {
    for (var i = 0; i < x.cPred.length; i++) {
        var p = x.cPred[i];
        if (p.hour === hour && p.avgConsumptionKwh > 0 && p.sampleCount >= 3) return p.avgConsumptionKwh;
    }
    return C.dayCons / 24;
};
function solarKwh(hour) { return x.fPH[hour] !== undefined ? x.fPH[hour] : 0; }
function clamp(v) { return Math.min(100, Math.max(C.minSoc, Math.round(v))); }

// Rozhodni mod per offset (pouziva sety z 03 + per-hour pravidla)
function resolveMode(off, soc, frac) {
    var hh = hp[off], hour = hh.hour, isSol = !!x.sO[off];
    var level = hh.levelBuy, buy = hh.buy, sell = hh.sell;
    if (C.manual !== "auto") return { m: C.manual, r: "Manuální režim, SOC " + Math.round(soc) + "%" };
    if (buy < 0) return { m: M.ZAP_NAK, r: (sell <= 0 ? "Záporný nákup + bez exportu" : "Max. odběr (záporný nákup)") + ", SOC " + Math.round(soc) + "%" };
    if (sell <= 0) {
        if (x.cO[off]) return { m: M.NABIJET, r: "Nabíjení ze sítě (ZP, ultra levná), SOC " + Math.round(soc) + "%" };
        return { m: M.ZAKAZ, r: "Zákaz přetoků, SOC " + Math.round(soc) + "%" };
    }
    if (x.cO[off]) {
        if (x.aCO[off]) return { m: M.NABIJET, r: "Arbitráž → " + x.aCO[off].targetHour + ":00, SOC " + Math.round(soc) + "%" };
        return { m: M.NABIJET, r: "Nabíjení ze sítě na " + Math.round(x.tSoc) + "%, SOC " + Math.round(soc) + "%" };
    }
    // FIX (12.5.2026): per-hour gate `soc > sellTarget` byl nekonzistentni s _simChrono node 03 fix.
    // Solver (node 03) jiz validoval pickedSet pres _simChrono globalni gate (endSoc >= sellTarget).
    // Tady stejny per-hour gate by zahodil legitimni prodeje, kde v okamzik prodeje soc < sellTarget,
    // ale po solar dni endSoc >= sellTarget. Per-hour zde proto jen safety net (minSafe = minSoc+nMargin).
    var minSafeForSell = C.minSoc + C.nMargin;
    if (x.sellMap[off] && soc > minSafeForSell) {
        var rC = x.replCost(off), netSell = sell * C.dchEff - C.amort, profit = netSell - rC;
        // UI: jen kratke info — zisk + drain trajektorie (per § 4.5 r. 287 SOC XX% format).
        var dropSoc = Math.max(C.minSoc, Math.round(soc - (C.maxFeed / 1000 * frac / C.dchEff / C.kap * 100)));
        return { m: M.PRODAVAT, r: "Prodej (zisk " + Math.round(profit * 10) / 10 + " Kč/kWh), SOC " + Math.round(soc) + "% → " + dropSoc + "%" };
    }
    if (isSol) {
        if (ppWorthIt(off, soc)) return { m: "prodavat_misto_nabijeni", r: "Solár do sítě místo nabití" };
        // FIX (12.5.2026): nibeAssigned[off] (pre-compute greedy by lvl) nahrazuje chronologicky chyceny pick.
        var nibePopis = nibeAssigned[off] ? " (NIBE topí)" : "";
        // Zachovan fix: smazana podminka `soc > C.minSoc` z draha detekce — solar pridava do baterie,
        // neni problem labelovat solarni hodinu jako drahou i pri SOC = minSoc (h8 misnomer fix).
        if (level >= C.DRAHA) return { m: M.NORMAL, r: "Solární + drahá hodina" + nibePopis + ", SOC " + Math.round(soc) + "%" };
        return { m: M.NORMAL, r: "Solární hodina" + nibePopis + ", SOC " + Math.round(soc) + "%" };
    }
    if (x.dO[off] && soc > C.minSoc) return { m: M.NORMAL, r: (level >= C.DRAHA ? "Drahá hodina" : "Střední cena") + ", SOC " + Math.round(soc) + "%" };
    if (soc <= C.minSoc) return { m: M.SETRIT, r: "Ochrana min. SOC, SOC " + Math.round(soc) + "%" };
    return { m: M.SETRIT, r: "Šetřím baterii, SOC " + Math.round(soc) + "%" };
}

// Simulace SOC pro dany mod
function simulujSOC(mod, hour, soc, frac, level) {
    var jeSol = hour >= x.solS && hour < x.solE;
    if (mod === "prodavat_misto_nabijeni") return soc; // prebytek exportovan, baterie idle
    if (mod === M.NABIJET) return Math.min(x.tSoc || 100, soc + (C.chKwh * frac * C.chEff / C.kap * 100));
    // FIX (12.5.2026): drain nemuze zvedat SOC nahoru -> clamp na minSoc (consistency s _simChrono).
    // Predchozi `Math.max(x.sellTarget, ...)` falesne ukazoval SOC=sellTarget i kdyz v okamzik prodeje
    // skutecny SOC byl pod sellTarget (drain reklame nahoru — bug v UI a v simulaci pro nasledne hodiny).
    if (mod === M.PRODAVAT) return Math.max(C.minSoc, soc - (C.maxFeed / 1000 * frac / C.dchEff / C.kap * 100));
    if (mod === M.SETRIT) {
        if (jeSol) {
            var sk = solarKwh(hour), c = consAt(hour);
            return Math.min(100, soc + Math.max(0, ((sk - c) * frac * C.chEff / C.kap) * 100));
        }
        return soc;
    }
    if (mod === M.NORMAL) {
        if (jeSol) {
            var sk2 = solarKwh(hour), c2 = consAt(hour);
            return Math.min(100, Math.max(C.minSoc, soc + ((sk2 - c2) * frac * C.chEff / C.kap) * 100));
        }
        // §4.9.1: NORMAL drain z baterie do domu deli /dchEff (vybijeci ucinnost ~90% — pro 1 kWh do domu baterie vyda 1.11 kWh).
        // Bez dchEff drain underestimovany ~10%/h, end-of-night SOC overestimovany (37% misto realnych 32%) — porusuje § 4.9 "pred prvni solarni hodinou ~25% SOC".
        return Math.max(C.minSoc, soc - (consAt(hour) * frac / C.dchEff / C.kap) * 100);
    }
    if (mod === M.ZAKAZ) return jeSol ? Math.min(100, soc + Math.max(0, (solarKwh(hour) - consAt(hour)) * frac * C.chEff / C.kap * 100)) : Math.max(C.minSoc, soc - (consAt(hour) * frac / C.dchEff / C.kap) * 100);
    if (mod === M.ZAP_NAK) return Math.min(100, soc + (C.chKwh * frac * C.chEff / C.kap * 100));
    if (mod === M.BAL) return jeSol ? Math.min(100, soc + (C.chKwh * frac * C.chEff / C.kap * 100)) : soc;
    return soc;
}

var nazevModu = { normal: "Normální provoz", setrit: "Šetřit baterii", nabijet_ze_site: "Nabíjet ze sítě", prodavat: "Prodávat do sítě", zakaz_pretoku: "Zákaz přetoků", "Balancování": "Balancování baterie", zaporna_nakupni_cena: "Záporný nákup", prodavat_misto_nabijeni: "Prodej přebytku do sítě" };
var remGain = new Array(hp.length + 1); remGain[hp.length] = 0;
for (var _rg = hp.length - 1; _rg >= 0; _rg--) { var _g = x.sO[_rg] ? Math.max(0, (solarKwh(hp[_rg].hour) - consAt(hp[_rg].hour)) * C.chEff / C.kap * 100) : 0; remGain[_rg] = remGain[_rg + 1] + _g; }
