for(var i=0;i<p.length;i++){var m=p[i].mode;if(m==="setrit")cS++;else if(m==="normal")cN++;else if(m==="nabijet_ze_site")cNb++;else if(m==="prodavat")cP++;else if(m==="Balancování")cB++;else if(m==="zaporna_nakupni_cena")cZN++;}
